#include <bits/stdc++.h>
using namespace std;
int b;
string fun(int num)
{
	string ans="";
	int x=num;
	while(x)
	{
		int t=x%b;
		if(t<10) ans=ans+(char)('0'+t);
		else  ans=ans+(char)('A'+t-10);
		x/=b;
	}
	reverse(ans.begin(),ans.end());
	if(ans[0]=='0') ans="1"+ans;
	return ans;
}
int main()
{
	cin>>b;
	for(int i=1;i<=300;i++)
	{
